mapper.select:
SELECT qe.qualitative_evaluation_id AS evaluation_id, qe.evaluation_period_id AS evaluation_period_id, ep.algorithm_version_id AS algorithm_version_id, qe.evaluatee_id AS employee_id, qe.evaluator_id AS evaluator_id, qe.evaluation_level AS evaluation_level, qe.second_evaluation_mode AS second_evaluation_mode, CASE WHEN qe.evaluation_level = 2 THEN base.score ELSE NULL END AS base_raw_score, qe.eval_comment AS comment_text, qe.input_method AS input_method, #{analysisVersion} AS analysis_version, COALESCE(qe.updated_at, qe.created_at) AS submitted_at FROM qualitative_evaluation qe LEFT JOIN qualitative_evaluation base ON base.evaluatee_id = qe.evaluatee_id AND base.evaluation_period_id = qe.evaluation_period_id AND base.evaluation_level = 1 LEFT JOIN evaluation_period ep ON ep.eval_period_id = qe.evaluation_period_id WHERE qe.status IN ('SUBMITTED', 'CONFIRMED') AND qe.evaluation_level IN (1, 2) AND ( ( qe.evaluation_level = 1 AND qe.eval_comment IS NOT NULL AND CHAR_LENGTH(TRIM(qe.eval_comment)) > 0 ) OR ( qe.evaluation_level = 2 AND ( qe.second_evaluation_mode = 'KEEP_FIRST_SCORE' OR ( qe.second_evaluation_mode = 'ANALYZE_COMMENT' AND qe.eval_comment IS NOT NULL AND CHAR_LENGTH(TRIM(qe.eval_comment)) > 0 ) ) ) )
AND qe.evaluation_period_id = #{evaluationPeriodId}
AND qe.evaluatee_id = #{employeeId}
AND qe.qualitative_evaluation_id = #{qualitativeEvaluationId}
AND qe.score IS NULL
ORDER BY qe.evaluation_period_id, qe.evaluatee_id, qe.evaluation_level, qe.qualitative_evaluation_id
